// TEMP: flags found in Android code
const codeFlags = ["Admin"];

// Firebase flags from Set node
const firebaseFlags = items[0].json.flags || [];

const codeSet = new Set(codeFlags);

const usedFirebaseFlags = firebaseFlags.filter(f => codeSet.has(f));
const unusedFirebaseFlags = firebaseFlags.filter(f => !codeSet.has(f));

return [
  {
    json: {
      codeFlags,
      usedFirebaseFlags,
      unusedFirebaseFlags
    }
  }
];

return items.map(item => {
  const code = item.json.code;

  // Simple regex examples
  const stringKeys = [...code.matchAll(/"([^"]+)"/g)].map(m => m[1]);

  return {
    json: {
      fileName: item.json.fileName,
      filePath: item.json.filePath,
      stringLiterals: [...new Set(stringKeys)]
    }
  };
});

return items.map(item => {
  const cleanKeys = item.json.stringLiterals.filter(key =>
    key.length <= 30 &&           // avoid long UI text
    !key.includes('\n') &&        // remove multiline
    !key.includes('$')            // remove template strings
  );

  return {
    json: {
      fileName: item.json.fileName,
      filePath: item.json.filePath,
      keys: [...new Set(cleanKeys)]
    }
  };
});

return items.map(item => {
  const featureFlags = [];
  const configKeys = [];
  const uiKeys = [];

  for (const key of item.json.keys) {
    if (/on\s|called/i.test(key)) {
      uiKeys.push(key);
    } else if (/admin|feature|enable|disable|flag/i.test(key)) {
      featureFlags.push(key);
    } else {
      configKeys.push(key);
    }
  }

  return {
    json: {
      fileName: item.json.fileName,
      filePath: item.json.filePath,
      featureFlags,
      configKeys,
      uiKeys
    }
  };
});

return items.map(item => {
  const base64Content = item.json.content;

  if (!base64Content) {
    // Skip items without content
    return null;
  }

  const buffer = Buffer.from(base64Content, 'base64');
  const text = buffer.toString('utf8');

  return {
    json: {
      code: text,
      filePath: item.json.path,
      fileName: item.json.name
    }
  };
}).filter(Boolean);

return [
  {
    json: {
      summary: {
        totalCodeFlags: items[0].json.codeFlags.length,
        totalFirebaseFlags:
          items[0].json.usedFirebaseFlags.length +
          items[0].json.unusedFirebaseFlags.length,
        unusedFirebaseFlagsCount:
          items[0].json.unusedFirebaseFlags.length
      },
      details: items[0].json
    }
  }
];

